// Compliant: Follows camelCase convention
generator<int> iota(int n = 0) {
    while(true) co_yield n++;
}

// Compliant: Starts with lowercase, descriptive name
task<void> processData() {
    co_await doWork();
}

// Compliant: Clear, well-named coroutine
task<int> calculateResult() {
    co_return 42;
}
